from mqtt_handler import MQTTHandler
from GameSession import GameSession
from GameMode import GameMode, TeamDeathmatch
from DeviceRegistry import DeviceRegistry
from PlayerProfile import PlayerProfile


class GameModeFactory:
    @staticmethod
    def get_available_modes():
        return {
            "1": ("Team Deathmatch", TeamDeathmatch),
            "2": ("Capture the Flag", GameMode),  # Placeholder, można rozszerzyć
            "3": ("King of the Hill", GameMode),   # Placeholder
        }

    @staticmethod
    def choose_mode(mode_id):
        modes = GameModeFactory.get_available_modes()
        if mode_id in modes:
            name, cls = modes[mode_id]
            return cls(name=name)
        return TeamDeathmatch(name="Team Deathmatch")  # Default


class ASGConnect:
    def __init__(self):
        self.registry = DeviceRegistry()
        self.mode = None  # Wybierany później
        self.session = None
        self.mqtt = None
        self.profiles = {}  # id to PlayerProfile

    def initialize_game_mode(self, mode_id="1"):  # Domyślnie Team Deathmatch
        self.mode = GameModeFactory.choose_mode(mode_id)
        self.session = GameSession(mqtt_handler=None, game_mode=self.mode, registry=self.registry)
        self.mqtt = MQTTHandler(game_session=self.session)
        self.session.mqtt = self.mqtt

    def start(self):
        """Uruchamia komponenty bez CLI menu"""
        if not self.mode:
            self.initialize_game_mode()  # Domyślny tryb
        self.mqtt.start()
        print(f"[SERVER] Serwer ASGConnect uruchomiony w trybie: {self.mode.name}.")

    def stop(self):
        """Zatrzymuje komponenty"""
        if self.mqtt:
            self.mqtt.stop()
        print("[SERVER] System zatrzymany.")

    def add_profile(self, nickname, role="Rekrut"):
        profile = PlayerProfile(nickname=nickname, role=role)
        self.profiles[profile.player_id] = profile
        return profile

    def edit_profile(self, profile_id, nickname=None, role=None):
        if profile_id in self.profiles:
            if nickname:
                self.profiles[profile_id].nickname = nickname
            if role:
                self.profiles[profile_id].role = role
            return True
        return False

    def delete_profile(self, profile_id):
        if profile_id in self.profiles:
            del self.profiles[profile_id]
            return True
        return False

    def get_profiles(self):
        return {pid: p.to_dict() for pid, p in self.profiles.items()}

    def send_config_to_all(self):
        """Wysyła konfigurację do wszystkich zarejestrowanych graczy"""
        for player in self.registry.get_all_players():
            self.session.sync_player(player)

