import time from DeviceTag import DeviceTag from PlayerProfile import PlayerProfile from ActivePlayer import ActivePlayer
class GameSession: def __init__(self, mqtt_handler, game_mode, registry, asg_app): self.mqtt = mqtt_handler self.mode = game_mode self.registry = registry self.asg_app = asg_app self.start_time = None self.is_running = False self.status = 'configuration' self.time_left = 0
def add_player(self, active_player_obj): """Rejestruje gracza w globalnym rejestrze""" self.registry.link_player(active_player_obj) print(f"[GAME] Zarejestrowano: {active_player_obj.profile.nickname}")
def start_round(self, time_mins=60): self.time_left = time_mins * 60 self.status = 'running' self.is_running = True # Pobieramy wszystkich z rejestru for player in self.registry.get_all_players(): self.sync_player(player) token = player.tag.generate_new_token() self.mqtt.send_command(player.tag.dev_eui, token, "START")
def stop_round(self): self.status = 'stopped' self.is_running = False
def reset_round(self): self.status = 'configuration' self.time_left = 0 self.is_running = False
""" Autorejestracja nowego urządzenia, które wysyła uplink, ale nie jest w bazie tagów. """ def auto_register_new_device(self, dev_eui):
tag = DeviceTag(dev_eui) self.registry.register_tag(tag) return tag
def create_active_players(self): for dev_eui, tag in self.registry._all_tags.items(): profile = self.registry.get_profile_by_eui(dev_eui) if profile is None: continue # tag bez profilu → pomiń
player = ActivePlayer( device_tag=tag, profile=profile, team=profile.team # jeśli profil ma team ) self.registry.link_player(player) self.add_player(player)
""" Autorejestracja nowego gracza, który wysyła uplink, ale nie jest w bazie graczy. Tworzy tymczasowy profil gracza na podstawie taga, można później edytować w panelu admina. """
def auto_register_new_profile(self, tag): profile = PlayerProfile( nickname=f"Player_{tag.dev_eui[-4:]}", role="Rekrut" ) self.registry.register_profile(profile, tag.dev_eui) self.asg_app.profiles[profile.player_id] = profile self.asg_app.save_profiles() print(f"[AUTO] Utworzono profil {profile.nickname} dla taga {tag.dev_eui}") return profile
def process_incoming_event(self, dev_eui, game_data, rssi, snr): # 1. Próba pobrania istniejącego gracza player = self.registry.get_player_by_eui(dev_eui)
# 2. Obsługa braku gracza (Auto-rejestracja) if not player: print(f"[SESSION] Nieznane urządzenie {dev_eui}. Uruchamiam auto-rejestrację.")
# Najpierw pobieramy/tworzymy sam TAG tag = self.auto_register_new_device(dev_eui)
# GWARDIA: Sprawdzamy czy obiekt tag w ogóle powstał if tag is None: print(f"[ERROR] Nie udało się stworzyć/pobrać taga dla {dev_eui}") return
# Tworzymy profil i gracza profile = self.auto_register_new_profile(tag) player = ActivePlayer(device_tag=tag, profile=profile, team=0)
# Rejestrujemy gracza w sesji self.add_player(player) print(f"[DEBUG] Pomyślnie zarejestrowano auto-gracza dla {dev_eui}")
# 3. OSTATECZNA WERYFIKACJA (Gwardia przed aktualizacją metryk) # Sprawdzamy czy player i player.tag istnieją przed kropką if not player or not hasattr(player, 'tag') or player.tag is None: print(f"[ERROR] Obiekt gracza lub taga dla {dev_eui} jest uszkodzony (NoneType)") return
# 4. AKTUALIZACJA METRYK (Bezpieczna) try: player.tag.update_metrics(rssi, snr) player.tag.last_seen = time.time() player.tag.status = "ONLINE" # To kluczowe dla frontendu except AttributeError as e: print(f"[ERROR] Błąd atrybutu status w obiekcie Tag: {e}") return
# 5. OBSŁUGA TYPÓW WIADOMOŚCI msg_type = game_data.get("type")
if msg_type == "TELEMETRY": # Używamy .get z domyślną wartością, aby nie wywalić się na braku klucza player.lat = game_data.get("lat", 0.0) player.lon = game_data.get("lon", 0.0) self._trigger_broadcast()
elif msg_type == "ACK_APP": token = game_data.get("token") if token is not None: player.tag.confirm_ack(token)
elif msg_type == "EVENT": event_status = game_data.get("status") if event_status == "KILLED": if self.mode: print(f"[GAME] Gracz {player.profile.nickname} został trafiony!") self.mode.on_hit(player, self) self._trigger_broadcast()
elif msg_type == "PING": # Bezpieczne sprawdzenie synchronizacji is_synced = getattr(player.tag, 'is_synced', True) if not is_synced: print(f"[GAME] Autorepair: Synchronizacja dla {player.profile.nickname}") self.sync_player(player)
def _trigger_broadcast(self): """Pomocnicza funkcja do odświeżania frontendu""" try: from web_server import broadcast_update broadcast_update() except Exception as e: print(f"[WS] Błąd broadcastu: {e}")
def sync_player(self, player): token = player.tag.generate_new_token()
self.mqtt.send_config( dev_eui=player.tag.dev_eui, token=token, team=player.team, game_type=1, # ID trybu gry (można wyciągnąć z self.mode) time_mins=60, allies_tot=self._count_team(player.team), enemies_tot=self._count_team(1 - player.team), nickname=player.profile.nickname ) player.tag.downlink_count += 1 # Zwiększamy licznik downlinków
def broadcast_state(self): if not self.is_running: return for player in self.registry.get_all_players(): update_data = self.mode.get_game_update_data(player, self) self.mqtt.send_update(player.tag.dev_eui, update_data["allies"], update_data["enemies"])
""" Zlicza graczy w danej drużynie """ def _count_team(self, team_id): return sum(1 for p in self.registry.get_all_players() if p.team == team_id)

import uuid


class PlayerProfile:
    def __init__(self, nickname, player_id=None, rank=None, role=None):
        self.player_id = player_id if player_id else str(uuid.uuid4())[:8]
        self.nickname = nickname
        self.rank = rank
        self.role = role
        self.games_played = 0
        self.killed_count = 0
        self.total_distance_km = 0.0

    def add_game_stats(self, distance):
        self.total_distance_km += distance
        self.games_played += 1

    def to_dict(self):
        return {
            "id": self.player_id,
            "nick": self.nickname,
            "rank": self.rank,
            "role": self.role,
            "stats": {
                "games": self.games_played
            }
        }

    def __repr__(self):
        return f"<PlayerProfile {self.nickname} | ID: {self.player_id} | Role: {self.role}>"

from fastapi import FastAPI, WebSocket
from fastapi.middleware.cors import CORSMiddleware
import uvicorn
import asyncio
from ASGConnect import ASGConnect  # Import klasy głównej
from ActivePlayer import ActivePlayer
import time

app = FastAPI()

main_loop = None



# CORS dla frontendu
app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],  # W produkcji ogranicz
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# Instancja aplikacji ASG
asg_app = ASGConnect()

# Lista połączonych WebSocket klientów
connected_clients = []

@app.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    connected_clients.append(websocket)
    print(f"[WS] Nowy klient podłączony. Razem: {len(connected_clients)}")
    try:
        # Wyślij początkową aktualizację
        broadcast_update()
        while True:
            data = await asyncio.wait_for(websocket.receive_text(), timeout=30.0)
    except asyncio.TimeoutError:
        # Timeout, send ping
        try:
            await websocket.send_json({"type": "PING"})
        except:
            pass
    except Exception as e:
        print(f"[WS] WebSocket error: {e}")
    finally:
        connected_clients.remove(websocket)
        print(f"[WS] Klient odłączony. Razem: {len(connected_clients)}")

"""
    Buduje słownik JSON graczy, wysyła do połączonych WebSocketów, bez blokowannia wątku (wywołane z MQTT)
"""


def broadcast_update():
    players_data = {}

    # Pobieramy kopię tagów, aby uniknąć błędów iteracji
    all_tags = list(asg_app.registry._all_tags.items())

    for dev_eui, tag in all_tags:
        if tag is None:
            continue

        player = asg_app.registry.get_player_by_eui(dev_eui)

        # Oblicz status połączenia na podstawie last_seen
        now = time.time()
        last_seen = getattr(tag, 'last_seen', 0)
        if now - last_seen < 60:  # < 1 min = ONLINE
            connection_status = "ONLINE"
        elif now - last_seen < 300:  # 1-5 min = TIMEOUT
            connection_status = "TIMEOUT"
        else:  # > 5 min = OFFLINE
            connection_status = "OFFLINE"

        # Budujemy dane techniczne (zawsze dostępne z taga)
        tag_info = {
            "status": connection_status,  # Status połączenia urządzenia
            "rssi": getattr(tag, 'rssi', -120),
            "uplink_count": getattr(tag, 'uplink_count', 0),
            "downlink_count": getattr(tag, 'downlink_count', 0),
            "last_seen": last_seen,
            "lat": 0.0,
            "lon": 0.0,
            "is_alive": False,
            "nickname": "NIEZNANY",
            "team": 0,
            "profile_id": None
        }

        # BEZPIECZNIK 2: Jeśli gracz istnieje, nadpisujemy dane profilowe
        if player is not None:
            p_status = getattr(player, 'status', 'ALIVE')
            tag_info.update({
                "is_alive": p_status == "ALIVE",
                "lat": getattr(player, 'lat', 0.0),
                "lon": getattr(player, 'lon', 0.0),
                "team": getattr(player, 'team', 0),
            })

            if player.profile:
                tag_info["nickname"] = getattr(player.profile, 'nickname', 'N/A')
                tag_info["profile_id"] = getattr(player.profile, 'player_id', None)

        players_data[dev_eui] = tag_info

    # Payload dla frontendu
    message = {
        "type": "UPDATE_PLAYERS",
        "data": players_data,
        "game_status": asg_app.session.status,
        "time_left": asg_app.session.time_left
    }

    # Wysłanie przez WebSocket (z zachowaniem main_loop)
    clients_copy = connected_clients.copy()
    for client in clients_copy:
        if main_loop:
            asyncio.run_coroutine_threadsafe(client.send_json(message), main_loop)


async def broadcast_loop():
    """Pętla wysyłająca aktualizacje co sekundę"""
    while True:
        await asyncio.sleep(1)

        changed = False
        # Przejdź przez wszystkie tagi i sprawdź timeout
        for dev_eui, tag in asg_app.registry._all_tags.items():
            # Wywołanie Twojej funkcji (zakładając, że tag to instancja z tą metodą)
            if tag.check_connection(timeout_seconds=120):
                changed = True
                print(f"[SYSTEM] Urządzenie {dev_eui} zmieniło status na TIMEOUT")

        if connected_clients:
            broadcast_update()

@app.post("/api/game/start")
async def start_game(data: dict = {}):
    time_mins = data.get("time_mins", 60)
    asg_app.session.start_round(time_mins=time_mins)
    broadcast_update()
    return {"status": "Game started"}

@app.post("/api/game/stop")
async def stop_game():
    asg_app.session.stop_round()
    broadcast_update()
    return {"status": "Game stopped"}

@app.post("/api/game/reset")
async def reset_game():
    asg_app.session.reset_round()
    asg_app.registry._tag_to_player = {}
    broadcast_update()
    return {"status": "Game reset"}

@app.post("/api/game/respawn/{dev_eui}")
async def respawn_player(dev_eui: str):
    player = asg_app.registry.get_player_by_eui(dev_eui.upper())
    if player:
        player.status = "ALIVE"
        token = player.tag.generate_new_token()
        asg_app.mqtt.send_command(dev_eui.upper(), token, "RESPAWN")
        broadcast_update()
        return {"status": f"Player {dev_eui} respawned"}
    return {"error": "Player not found"}

@app.post("/api/spoof")
async def spoof_gps(data: dict):
    dev_eui = data.get("dev_eui")
    lat = data.get("lat")
    lon = data.get("lon")
    player = asg_app.registry.get_player_by_eui(dev_eui.upper())
    if player:
        player.lat = lat
        player.lon = lon
        broadcast_update()
        return {"status": f"GPS spoofed for {dev_eui}"}
    return {"error": "Player not found"}

@app.get("/api/profiles")
async def get_profiles():
    return asg_app.get_profiles()

@app.post("/api/profiles")
async def add_profile(data: dict):
    nickname = data.get("nick")
    role = data.get("role", "Rekrut")
    if nickname:
        profile = asg_app.add_profile(nickname, role)
        return profile.to_dict()
    return {"error": "Nickname required"}


@app.put("/api/profiles/{profile_id}") #pobieranie stringa z URL i parsownaie JSON -> dict
async def edit_profile(profile_id: str, data: dict): #type hinting, jak sparsować
    nickname = data.get("nick")
    role = data.get("role")
    if asg_app.edit_profile(profile_id, nickname, role):
        return {"status": "Updated"}
    return {"error": "Profile not found"}

@app.delete("/api/profiles/{profile_id}") #path parameter
async def delete_profile(profile_id: str):
    if asg_app.delete_profile(profile_id):
        return {"status": "Deleted"}
    return {"error": "Profile not found"}


@app.post("/api/game/mode")
async def set_game_mode(data: dict):
    mode_id = data.get("mode_id")
    if mode_id:
        asg_app.initialize_game_mode(mode_id)
        return {"status": f"Mode set to {asg_app.mode.name}"}
    return {"error": "Mode ID required"}


"""
    Endpointy do przypisywania drużyny i profilu do ActivePalyer
"""
@app.put("/api/players/{dev_eui}/team")
async def assign_team(dev_eui: str, data: dict):
    team_id = data.get("team")
    player = asg_app.registry.get_player_by_eui(dev_eui.upper())
    if player:
        player.team = int(team_id)
        asg_app.session.sync_player(player)
        broadcast_update()
        return {"status": "Team assigned"}
    return {"error": "Player not found"}

@app.put("/api/players/{dev_eui}/profile")
async def assign_profile(dev_eui: str, data: dict):
    profile_id = data.get("profile_id")
    dev_eui_upper = dev_eui.upper()
    player = asg_app.registry.get_player_by_eui(dev_eui_upper)
    tag = asg_app.registry.get_tag(dev_eui_upper)
    if not tag:
        return {"error": "Tag not found"}
    if player:
        if profile_id and profile_id in asg_app.profiles:
            player.profile = asg_app.profiles[profile_id]
        else:
            player.profile = None
    else:
        # Jeśli nie ma gracza, ale jest tag, utwórz nowego ActivePlayer z profilem
        if profile_id and profile_id in asg_app.profiles:
            profile = asg_app.profiles[profile_id]
            player = ActivePlayer(device_tag=tag, profile=profile, team=0)  # domyślna drużyna
            asg_app.session.add_player(player)
        else:
            return {"error": "Profile required to create player"}
    asg_app.session.sync_player(player)
    broadcast_update()
    return {"status": "Profile assigned"}

async def main():
    global main_loop
    main_loop = asyncio.get_running_loop()
    print("[APP] Inicjalizacja ASGConnect...")

    # Uruchom ASGConnect
    asg_app.start()

    # Uruchom broadcast loop
    asyncio.create_task(broadcast_loop())
    print("[APP] Broadcast loop uruchomiony")

    # Uruchom serwer web
    print("[APP] Uruchamianie serwera webowego...")
    config = uvicorn.Config(app, host="127.0.0.1", port=8000, log_level="info")
    server = uvicorn.Server(config)
    await server.serve()

if __name__ == "__main__":
    asyncio.run(main())

from fastapi import FastAPI, WebSocket
from fastapi.middleware.cors import CORSMiddleware
import uvicorn
